-- Finance Phase 7: banking, credit scores, loans, repayments and staged financial distress.
-- Banking references the unified financial_accounts/financial_transactions/financial_ledger_entries ledger.
-- Bank balances are derived from linked finance accounts; borrowed principal is classified as liability funding, not income.

ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'bank_deposit';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'bank_withdrawal';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'savings_interest';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'loan_disbursement';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'loan_principal_repayment';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'loan_interest_repayment';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'loan_fee';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'loan_recovery_payment';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'loan_refinance_settlement';

DO $$ BEGIN CREATE TYPE public.banking_provider_type AS ENUM ('retail_bank','commercial_bank','international_bank','music_industry_lender','community_bank','government_backed_lender'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.banking_provider_status AS ENUM ('draft','active','restricted','suspended','closed'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.banking_customer_status AS ENUM ('active','restricted','frozen','default_recovery','closed'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.identity_verification_status AS ENUM ('not_started','placeholder_pending','verified','review_required'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.bank_account_type AS ENUM ('current','savings','business_current','band_account','tax_reserve','loan_disbursement_placeholder','restricted','currency_account'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.bank_account_status AS ENUM ('pending','active','restricted','frozen','closing','closed'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.loan_product_status AS ENUM ('draft','active','restricted','retired'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.loan_rate_type AS ENUM ('fixed','variable_placeholder'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.loan_purpose AS ENUM ('personal_emergency','education','equipment','travel','band_recording','band_touring','band_equipment','company_working_capital','company_equipment','company_expansion','company_payroll_recovery','company_premises_improvement','refinancing'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.loan_application_status AS ENUM ('draft','submitted','evaluating','additional_information_required','approved','conditionally_approved','rejected','offer_issued','offer_accepted','offer_declined','expired','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.loan_contract_status AS ENUM ('pending_activation','active','grace_period','delinquent','defaulted','restructured','refinanced','paid_off','written_off','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.loan_schedule_line_status AS ENUM ('scheduled','due','paid','partial','grace_period','late','seriously_late','final_warning','defaulted','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.credit_band AS ENUM ('excellent','very_good','good','fair','weak','poor','severe_risk'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.insolvency_assessment_outcome AS ENUM ('solvent','liquidity_warning','financially_distressed','at_risk_of_insolvency','insolvent'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

ALTER TYPE public.band_finance_permission ADD VALUE IF NOT EXISTS 'view_borrowing';
ALTER TYPE public.band_finance_permission ADD VALUE IF NOT EXISTS 'apply_for_loan';
ALTER TYPE public.band_finance_permission ADD VALUE IF NOT EXISTS 'review_loan_offer';
ALTER TYPE public.band_finance_permission ADD VALUE IF NOT EXISTS 'accept_loan';
ALTER TYPE public.band_finance_permission ADD VALUE IF NOT EXISTS 'change_repayment_account';
ALTER TYPE public.band_finance_permission ADD VALUE IF NOT EXISTS 'make_early_repayment';
ALTER TYPE public.band_finance_permission ADD VALUE IF NOT EXISTS 'request_restructuring';
ALTER TYPE public.band_finance_permission ADD VALUE IF NOT EXISTS 'refinance_loan';
ALTER TYPE public.band_finance_permission ADD VALUE IF NOT EXISTS 'view_credit_report';

CREATE TABLE IF NOT EXISTS public.banking_providers (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), provider_code text NOT NULL UNIQUE, name text NOT NULL, brand_name text NOT NULL,
  home_country text NOT NULL, supported_countries text[] NOT NULL, supported_currencies char(3)[] NOT NULL,
  provider_type public.banking_provider_type NOT NULL, status public.banking_provider_status NOT NULL DEFAULT 'draft',
  reputation_score integer NOT NULL CHECK (reputation_score BETWEEN 0 AND 100), stability_rating integer NOT NULL CHECK (stability_rating BETWEEN 0 AND 100),
  risk_appetite integer NOT NULL CHECK (risk_appetite BETWEEN 0 AND 100), service_quality_rating integer NOT NULL CHECK (service_quality_rating BETWEEN 0 AND 100),
  base_deposit_rate_basis_points integer NOT NULL DEFAULT 0, base_lending_margin_basis_points integer NOT NULL DEFAULT 300,
  account_fees jsonb NOT NULL DEFAULT '{}', loan_fees jsonb NOT NULL DEFAULT '{}', minimum_credit_score integer NOT NULL DEFAULT 0 CHECK (minimum_credit_score BETWEEN 0 AND 1000),
  maximum_exposure_minor bigint NOT NULL CHECK (maximum_exposure_minor > 0), product_configuration jsonb NOT NULL DEFAULT '{}',
  lending_frozen boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}'
);

CREATE TABLE IF NOT EXISTS public.banking_customer_profiles (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), owner_type public.financial_owner_type NOT NULL CHECK (owner_type IN ('player','band','company')), owner_id uuid NOT NULL,
  primary_country text NOT NULL DEFAULT 'United States', tax_jurisdiction text, banking_status public.banking_customer_status NOT NULL DEFAULT 'active', identity_verification_status public.identity_verification_status NOT NULL DEFAULT 'placeholder_pending',
  credit_score integer NOT NULL DEFAULT 600 CHECK (credit_score BETWEEN 0 AND 1000), credit_band public.credit_band NOT NULL DEFAULT 'fair',
  total_deposits_minor bigint NOT NULL DEFAULT 0, total_borrowing_minor bigint NOT NULL DEFAULT 0, available_credit_minor bigint NOT NULL DEFAULT 0,
  missed_payments integer NOT NULL DEFAULT 0, defaults_count integer NOT NULL DEFAULT 0, banking_relationship_start date NOT NULL DEFAULT CURRENT_DATE,
  last_evaluated_at timestamptz, risk_flags jsonb NOT NULL DEFAULT '{}', metadata jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()), UNIQUE(owner_type,owner_id)
);

CREATE TABLE IF NOT EXISTS public.bank_accounts (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), provider_id uuid NOT NULL REFERENCES public.banking_providers(id), owner_type public.financial_owner_type NOT NULL CHECK (owner_type IN ('player','band','company')), owner_id uuid NOT NULL,
  linked_finance_account_id uuid NOT NULL UNIQUE REFERENCES public.financial_accounts(id), account_type public.bank_account_type NOT NULL, currency_code char(3) NOT NULL,
  interest_configuration jsonb NOT NULL DEFAULT '{}', fee_configuration jsonb NOT NULL DEFAULT '{}', status public.bank_account_status NOT NULL DEFAULT 'pending',
  opened_at timestamptz, closed_at timestamptz, minimum_balance_minor bigint NOT NULL DEFAULT 0 CHECK (minimum_balance_minor >= 0),
  withdrawal_restrictions jsonb NOT NULL DEFAULT '{}', deposit_restrictions jsonb NOT NULL DEFAULT '{}', metadata jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()),
  CONSTRAINT bank_accounts_currency_format CHECK (currency_code ~ '^[A-Z]{3}$')
);
CREATE UNIQUE INDEX IF NOT EXISTS bank_accounts_one_active_type_currency_idx ON public.bank_accounts(owner_type,owner_id,provider_id,account_type,currency_code) WHERE status IN ('pending','active','restricted','frozen');

CREATE TABLE IF NOT EXISTS public.deposit_interest_accruals (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), bank_account_id uuid NOT NULL REFERENCES public.bank_accounts(id), accrual_period_start date NOT NULL, accrual_period_end date NOT NULL,
  opening_eligible_balance_minor bigint NOT NULL CHECK (opening_eligible_balance_minor >= 0), rate_basis_points integer NOT NULL, accrued_amount_minor bigint NOT NULL DEFAULT 0 CHECK (accrued_amount_minor >= 0), paid_amount_minor bigint NOT NULL DEFAULT 0,
  currency_code char(3) NOT NULL, rounding_minor bigint NOT NULL DEFAULT 0, linked_transaction_id uuid UNIQUE REFERENCES public.financial_transactions(id), calculation_version text NOT NULL DEFAULT 'deposit_interest_v1_daily_actual_365',
  tax_classification text NOT NULL DEFAULT 'taxable_interest_income', status text NOT NULL DEFAULT 'accrued', idempotency_key text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}',
  CONSTRAINT deposit_interest_period CHECK (accrual_period_end >= accrual_period_start)
);

CREATE TABLE IF NOT EXISTS public.loan_products (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), provider_id uuid NOT NULL REFERENCES public.banking_providers(id), product_code text NOT NULL UNIQUE, product_name text NOT NULL,
  eligible_owner_types public.financial_owner_type[] NOT NULL, supported_currencies char(3)[] NOT NULL, minimum_amount_minor bigint NOT NULL CHECK(minimum_amount_minor>0), maximum_amount_minor bigint NOT NULL CHECK(maximum_amount_minor>=minimum_amount_minor),
  minimum_term_months integer NOT NULL CHECK(minimum_term_months>0), maximum_term_months integer NOT NULL CHECK(maximum_term_months>=minimum_term_months), base_interest_rate_basis_points integer NOT NULL,
  risk_margin_rules jsonb NOT NULL DEFAULT '{}', origination_fee_basis_points integer NOT NULL DEFAULT 0, origination_fee_flat_minor bigint NOT NULL DEFAULT 0, early_repayment_fee_basis_points integer NOT NULL DEFAULT 0,
  late_payment_rule jsonb NOT NULL DEFAULT '{"type":"flat","flat_fee_minor":500,"cap_minor":2500}', grace_period_days integer NOT NULL DEFAULT 7, minimum_credit_score integer NOT NULL DEFAULT 0 CHECK(minimum_credit_score BETWEEN 0 AND 1000),
  income_requirement_minor bigint NOT NULL DEFAULT 0, affordability_threshold_basis_points integer NOT NULL DEFAULT 3500, collateral_required boolean NOT NULL DEFAULT false, guarantor_required boolean NOT NULL DEFAULT false,
  refinancing_allowed boolean NOT NULL DEFAULT true, allowed_purposes public.loan_purpose[] NOT NULL, status public.loan_product_status NOT NULL DEFAULT 'draft', rate_type public.loan_rate_type NOT NULL DEFAULT 'fixed', payment_frequency public.recurring_obligation_frequency NOT NULL DEFAULT 'monthly',
  purpose_restrictions jsonb NOT NULL DEFAULT '{}', effective_start_date date NOT NULL DEFAULT CURRENT_DATE, effective_end_date date, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}'
);

CREATE TABLE IF NOT EXISTS public.loan_applications (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), applicant_type public.financial_owner_type NOT NULL CHECK(applicant_type IN ('player','band','company')), applicant_id uuid NOT NULL, provider_id uuid NOT NULL REFERENCES public.banking_providers(id), product_id uuid NOT NULL REFERENCES public.loan_products(id),
  requested_amount_minor bigint NOT NULL CHECK(requested_amount_minor>0), currency_code char(3) NOT NULL, requested_term_months integer NOT NULL CHECK(requested_term_months>0), purpose public.loan_purpose NOT NULL, related_entity_type text, related_entity_id uuid, declared_expected_use text,
  income_snapshot jsonb NOT NULL DEFAULT '{}', expense_snapshot jsonb NOT NULL DEFAULT '{}', debt_snapshot jsonb NOT NULL DEFAULT '{}', credit_score_snapshot integer NOT NULL DEFAULT 600, affordability_result jsonb NOT NULL DEFAULT '{}', risk_result jsonb NOT NULL DEFAULT '{}',
  status public.loan_application_status NOT NULL DEFAULT 'submitted', submitted_at timestamptz NOT NULL DEFAULT timezone('utc',now()), reviewed_at timestamptz, expiry_at timestamptz NOT NULL DEFAULT timezone('utc',now()) + interval '14 days', decision_reason text, offered_terms jsonb NOT NULL DEFAULT '{}', created_by_profile_id uuid REFERENCES public.profiles(id), idempotency_key text NOT NULL UNIQUE, metadata jsonb NOT NULL DEFAULT '{}'
);
CREATE UNIQUE INDEX IF NOT EXISTS loan_applications_duplicate_active_idx ON public.loan_applications(applicant_type,applicant_id,product_id,purpose,currency_code) WHERE status IN ('draft','submitted','evaluating','approved','conditionally_approved','offer_issued');

CREATE TABLE IF NOT EXISTS public.underwriting_results (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), application_id uuid NOT NULL UNIQUE REFERENCES public.loan_applications(id) ON DELETE CASCADE, approved boolean NOT NULL, maximum_approved_amount_minor bigint NOT NULL DEFAULT 0, offered_interest_rate_basis_points integer, offered_term_months integer, scheduled_payment_minor bigint, total_interest_minor bigint, total_repayment_minor bigint, fees_minor bigint NOT NULL DEFAULT 0, affordability_ratio_basis_points integer NOT NULL DEFAULT 0, risk_band text NOT NULL, approval_reasons text[] NOT NULL DEFAULT '{}', rejection_reasons text[] NOT NULL DEFAULT '{}', calculation_version text NOT NULL DEFAULT 'underwriting_v1_transparent_affordability', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}');
CREATE TABLE IF NOT EXISTS public.loan_offers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), application_id uuid NOT NULL UNIQUE REFERENCES public.loan_applications(id), principal_minor bigint NOT NULL, currency_code char(3) NOT NULL, interest_rate_basis_points integer NOT NULL, rate_type public.loan_rate_type NOT NULL DEFAULT 'fixed', term_months integer NOT NULL, payment_frequency public.recurring_obligation_frequency NOT NULL, scheduled_payment_minor bigint NOT NULL, origination_fee_minor bigint NOT NULL DEFAULT 0, total_interest_minor bigint NOT NULL DEFAULT 0, total_repayment_minor bigint NOT NULL, first_payment_date date NOT NULL, grace_period_days integer NOT NULL, early_repayment_terms jsonb NOT NULL DEFAULT '{}', late_payment_terms jsonb NOT NULL DEFAULT '{}', security_placeholder jsonb NOT NULL DEFAULT '{}', offer_expires_at timestamptz NOT NULL, calculation_version text NOT NULL DEFAULT 'loan_offer_v1_fixed_equal_instalment', status text NOT NULL DEFAULT 'issued', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), accepted_at timestamptz, declined_at timestamptz, metadata jsonb NOT NULL DEFAULT '{}');

CREATE TABLE IF NOT EXISTS public.loan_contracts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), borrower_type public.financial_owner_type NOT NULL CHECK(borrower_type IN ('player','band','company')), borrower_id uuid NOT NULL, provider_id uuid NOT NULL REFERENCES public.banking_providers(id), product_id uuid NOT NULL REFERENCES public.loan_products(id), offer_id uuid UNIQUE REFERENCES public.loan_offers(id), repayment_bank_account_id uuid REFERENCES public.bank_accounts(id), disbursement_bank_account_id uuid REFERENCES public.bank_accounts(id), principal_minor bigint NOT NULL CHECK(principal_minor>0), currency_code char(3) NOT NULL, outstanding_principal_minor bigint NOT NULL CHECK(outstanding_principal_minor>=0), accrued_interest_minor bigint NOT NULL DEFAULT 0, interest_rate_basis_points integer NOT NULL, rate_type public.loan_rate_type NOT NULL DEFAULT 'fixed', term_months integer NOT NULL, start_date date NOT NULL DEFAULT CURRENT_DATE, maturity_date date NOT NULL, payment_frequency public.recurring_obligation_frequency NOT NULL DEFAULT 'monthly', scheduled_payment_minor bigint NOT NULL, next_payment_date date, total_payments integer NOT NULL, payments_made integer NOT NULL DEFAULT 0, amount_repaid_minor bigint NOT NULL DEFAULT 0, interest_paid_minor bigint NOT NULL DEFAULT 0, fees_paid_minor bigint NOT NULL DEFAULT 0, status public.loan_contract_status NOT NULL DEFAULT 'pending_activation', purpose public.loan_purpose NOT NULL, linked_entity_type text, linked_entity_id uuid, credit_score_at_origination integer NOT NULL, affordability_snapshot jsonb NOT NULL DEFAULT '{}', contract_version integer NOT NULL DEFAULT 1, refinance_count integer NOT NULL DEFAULT 0, disbursement_transaction_id uuid UNIQUE REFERENCES public.financial_transactions(id), recurring_obligation_id uuid UNIQUE REFERENCES public.recurring_financial_obligations(id), created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), completed_at timestamptz, defaulted_at timestamptz, metadata jsonb NOT NULL DEFAULT '{}');

CREATE TABLE IF NOT EXISTS public.loan_schedule_lines (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), loan_contract_id uuid NOT NULL REFERENCES public.loan_contracts(id) ON DELETE CASCADE, schedule_version integer NOT NULL DEFAULT 1, instalment_number integer NOT NULL, due_date date NOT NULL, opening_principal_minor bigint NOT NULL, scheduled_principal_minor bigint NOT NULL DEFAULT 0, scheduled_interest_minor bigint NOT NULL DEFAULT 0, scheduled_fee_minor bigint NOT NULL DEFAULT 0, total_due_minor bigint NOT NULL, amount_paid_minor bigint NOT NULL DEFAULT 0, principal_paid_minor bigint NOT NULL DEFAULT 0, interest_paid_minor bigint NOT NULL DEFAULT 0, fee_paid_minor bigint NOT NULL DEFAULT 0, status public.loan_schedule_line_status NOT NULL DEFAULT 'scheduled', payment_transaction_id uuid REFERENCES public.financial_transactions(id), days_overdue integer NOT NULL DEFAULT 0, late_fee_applied boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), UNIQUE(loan_contract_id,schedule_version,instalment_number));
CREATE TABLE IF NOT EXISTS public.loan_payments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), loan_contract_id uuid NOT NULL REFERENCES public.loan_contracts(id), schedule_line_id uuid REFERENCES public.loan_schedule_lines(id), amount_minor bigint NOT NULL CHECK(amount_minor>0), principal_minor bigint NOT NULL DEFAULT 0, interest_minor bigint NOT NULL DEFAULT 0, fee_minor bigint NOT NULL DEFAULT 0, currency_code char(3) NOT NULL, payment_type text NOT NULL DEFAULT 'scheduled', transaction_id uuid UNIQUE REFERENCES public.financial_transactions(id), conversion_quote_id uuid REFERENCES public.currency_conversion_quotes(id), idempotency_key text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}');
CREATE TABLE IF NOT EXISTS public.loan_delinquency_records (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), loan_contract_id uuid NOT NULL REFERENCES public.loan_contracts(id), schedule_line_id uuid NOT NULL REFERENCES public.loan_schedule_lines(id), stage public.loan_schedule_line_status NOT NULL, days_overdue integer NOT NULL, credit_impact_points integer NOT NULL DEFAULT 0, late_fee_minor bigint NOT NULL DEFAULT 0, notification_key text, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), UNIQUE(schedule_line_id,stage));
CREATE TABLE IF NOT EXISTS public.loan_default_records (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), loan_contract_id uuid NOT NULL UNIQUE REFERENCES public.loan_contracts(id), defaulted_amount_minor bigint NOT NULL, principal_minor bigint NOT NULL, interest_minor bigint NOT NULL DEFAULT 0, fees_minor bigint NOT NULL DEFAULT 0, defaulted_at timestamptz NOT NULL DEFAULT timezone('utc',now()), recovery_options jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.loan_restructurings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), loan_contract_id uuid NOT NULL REFERENCES public.loan_contracts(id), previous_schedule_version integer NOT NULL, new_schedule_version integer NOT NULL, proposed_terms jsonb NOT NULL, status text NOT NULL DEFAULT 'offered', borrower_accepted_at timestamptz, lender_approved_at timestamptz, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), UNIQUE(loan_contract_id,new_schedule_version));
CREATE TABLE IF NOT EXISTS public.loan_refinance_records (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), old_loan_contract_id uuid NOT NULL REFERENCES public.loan_contracts(id), new_loan_contract_id uuid UNIQUE REFERENCES public.loan_contracts(id), application_id uuid UNIQUE REFERENCES public.loan_applications(id), settlement_transaction_id uuid UNIQUE REFERENCES public.financial_transactions(id), payoff_amount_minor bigint NOT NULL, refinancing_fee_minor bigint NOT NULL DEFAULT 0, status text NOT NULL DEFAULT 'completed', idempotency_key text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.credit_score_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), owner_type public.financial_owner_type NOT NULL CHECK(owner_type IN ('player','band','company')), owner_id uuid NOT NULL, previous_score integer NOT NULL, new_score integer NOT NULL CHECK(new_score BETWEEN 0 AND 1000), previous_band public.credit_band NOT NULL, new_band public.credit_band NOT NULL, reason_code text NOT NULL, public_summary text NOT NULL, related_entity_type text, related_entity_id uuid, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}');
CREATE TABLE IF NOT EXISTS public.provider_exposure_snapshots (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), provider_id uuid NOT NULL REFERENCES public.banking_providers(id), currency_code char(3) NOT NULL, loans_outstanding_minor bigint NOT NULL DEFAULT 0, customer_deposits_minor bigint NOT NULL DEFAULT 0, interest_received_minor bigint NOT NULL DEFAULT 0, interest_paid_minor bigint NOT NULL DEFAULT 0, fees_received_minor bigint NOT NULL DEFAULT 0, defaults_minor bigint NOT NULL DEFAULT 0, write_offs_minor bigint NOT NULL DEFAULT 0, new_lending_minor bigint NOT NULL DEFAULT 0, repayments_minor bigint NOT NULL DEFAULT 0, delinquency_rate_basis_points integer NOT NULL DEFAULT 0, risk_exposure jsonb NOT NULL DEFAULT '{}', snapshot_at timestamptz NOT NULL DEFAULT timezone('utc',now()), UNIQUE(provider_id,currency_code,snapshot_at));
CREATE TABLE IF NOT EXISTS public.debt_snapshots (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), owner_type public.financial_owner_type NOT NULL CHECK(owner_type IN ('player','band','company')), owner_id uuid NOT NULL, currency_code char(3) NOT NULL, total_debt_minor bigint NOT NULL DEFAULT 0, outstanding_principal_minor bigint NOT NULL DEFAULT 0, accrued_interest_minor bigint NOT NULL DEFAULT 0, scheduled_payments_minor bigint NOT NULL DEFAULT 0, next_payment_date date, payments_due_week_minor bigint NOT NULL DEFAULT 0, overdue_amount_minor bigint NOT NULL DEFAULT 0, total_remaining_repayment_minor bigint NOT NULL DEFAULT 0, debt_service_ratio_basis_points integer NOT NULL DEFAULT 0, credit_score integer NOT NULL DEFAULT 600, credit_band public.credit_band NOT NULL DEFAULT 'fair', generated_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}', UNIQUE(owner_type,owner_id,currency_code,generated_at));
CREATE TABLE IF NOT EXISTS public.banking_audit_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), actor_profile_id uuid REFERENCES public.profiles(id), action text NOT NULL, entity_type text NOT NULL, entity_id uuid, provider_id uuid REFERENCES public.banking_providers(id), previous_value jsonb, new_value jsonb, reason text NOT NULL, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}');

CREATE OR REPLACE FUNCTION public.credit_band_for_score(p_score integer) RETURNS public.credit_band LANGUAGE sql IMMUTABLE AS $$ SELECT CASE WHEN p_score >= 850 THEN 'excellent'::public.credit_band WHEN p_score >= 760 THEN 'very_good'::public.credit_band WHEN p_score >= 670 THEN 'good'::public.credit_band WHEN p_score >= 560 THEN 'fair'::public.credit_band WHEN p_score >= 450 THEN 'weak'::public.credit_band WHEN p_score >= 300 THEN 'poor'::public.credit_band ELSE 'severe_risk'::public.credit_band END $$;
CREATE OR REPLACE FUNCTION public.record_credit_score_event(p_owner_type public.financial_owner_type,p_owner_id uuid,p_delta integer,p_reason text,p_summary text,p_related_type text DEFAULT NULL,p_related_id uuid DEFAULT NULL) RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE prof public.banking_customer_profiles; ns integer; nb public.credit_band; BEGIN SELECT * INTO prof FROM public.banking_customer_profiles WHERE owner_type=p_owner_type AND owner_id=p_owner_id FOR UPDATE; IF prof.id IS NULL THEN INSERT INTO public.banking_customer_profiles(owner_type,owner_id) VALUES(p_owner_type,p_owner_id) RETURNING * INTO prof; END IF; ns := LEAST(1000,GREATEST(0,prof.credit_score+p_delta)); nb := public.credit_band_for_score(ns); UPDATE public.banking_customer_profiles SET credit_score=ns, credit_band=nb, last_evaluated_at=timezone('utc',now()), updated_at=timezone('utc',now()) WHERE id=prof.id; INSERT INTO public.credit_score_events(owner_type,owner_id,previous_score,new_score,previous_band,new_band,reason_code,public_summary,related_entity_type,related_entity_id) VALUES(p_owner_type,p_owner_id,prof.credit_score,ns,prof.credit_band,nb,p_reason,p_summary,p_related_type,p_related_id); RETURN ns; END $$;

CREATE OR REPLACE FUNCTION public.calculate_equal_instalment_schedule(p_principal_minor bigint,p_rate_bps integer,p_term_months integer,p_first_due date DEFAULT (CURRENT_DATE + interval '1 month')::date) RETURNS TABLE(instalment_number integer,due_date date,opening_principal_minor bigint,scheduled_principal_minor bigint,scheduled_interest_minor bigint,total_due_minor bigint) LANGUAGE plpgsql STABLE AS $$ DECLARE rem bigint:=p_principal_minor; i int; interest bigint; principal bigint; total_interest bigint:=0; base_principal bigint; BEGIN IF p_principal_minor<=0 OR p_term_months<=0 THEN RAISE EXCEPTION 'invalid schedule input'; END IF; base_principal := floor(p_principal_minor::numeric / p_term_months)::bigint; FOR i IN 1..p_term_months LOOP interest := round(rem::numeric * p_rate_bps::numeric / 10000 / 12)::bigint; principal := CASE WHEN i=p_term_months THEN rem ELSE LEAST(rem,base_principal) END; total_interest := total_interest + interest; RETURN QUERY SELECT i, (p_first_due + ((i-1)||' months')::interval)::date, rem, principal, interest, principal + interest; rem := rem - principal; END LOOP; END $$;

CREATE OR REPLACE FUNCTION public.open_bank_account(p_owner_type public.financial_owner_type,p_owner_id uuid,p_provider_id uuid,p_account_type public.bank_account_type,p_currency char(3),p_idempotency_key text DEFAULT NULL) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE fa public.financial_accounts; ba uuid; provider public.banking_providers; BEGIN SELECT * INTO provider FROM public.banking_providers WHERE id=p_provider_id AND status IN ('active','restricted'); IF provider.id IS NULL OR NOT (p_currency = ANY(provider.supported_currencies)) THEN RAISE EXCEPTION 'provider does not support account'; END IF; SELECT id INTO ba FROM public.bank_accounts WHERE metadata->>'idempotency_key'=p_idempotency_key AND p_idempotency_key IS NOT NULL; IF ba IS NOT NULL THEN RETURN ba; END IF; fa := public.get_or_create_primary_financial_account(p_owner_type,p_owner_id,initcap(p_account_type::text)||' bank account',p_currency); UPDATE public.financial_accounts SET account_purpose='bank_'||p_account_type::text, currency_code=p_currency, default_currency_code=p_currency WHERE id=fa.id; INSERT INTO public.bank_accounts(provider_id,owner_type,owner_id,linked_finance_account_id,account_type,currency_code,status,opened_at,interest_configuration,metadata) VALUES(p_provider_id,p_owner_type,p_owner_id,fa.id,p_account_type,p_currency,'active',timezone('utc',now()),jsonb_build_object('annual_rate_bps',provider.base_deposit_rate_basis_points,'payment_frequency','monthly'),jsonb_build_object('idempotency_key',p_idempotency_key)) ON CONFLICT DO NOTHING RETURNING id INTO ba; IF ba IS NULL THEN SELECT id INTO ba FROM public.bank_accounts WHERE linked_finance_account_id=fa.id; END IF; INSERT INTO public.banking_audit_events(action,entity_type,entity_id,provider_id,reason,new_value) VALUES('bank_account_opened','bank_account',ba,p_provider_id,'account opened through server function',jsonb_build_object('owner_type',p_owner_type,'currency',p_currency)); RETURN ba; END $$;

CREATE OR REPLACE FUNCTION public.evaluate_loan_application(p_application_id uuid) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE app public.loan_applications; prod public.loan_products; prov public.banking_providers; prof public.banking_customer_profiles; max_amt bigint; rate int; sched record; payment bigint:=0; total_interest bigint:=0; approved boolean; reasons text[]:='{}'; rejections text[]:='{}'; res uuid; exposure bigint; BEGIN SELECT * INTO app FROM public.loan_applications WHERE id=p_application_id FOR UPDATE; SELECT * INTO prod FROM public.loan_products WHERE id=app.product_id; SELECT * INTO prov FROM public.banking_providers WHERE id=app.provider_id; INSERT INTO public.banking_customer_profiles(owner_type,owner_id) VALUES(app.applicant_type,app.applicant_id) ON CONFLICT DO NOTHING; SELECT * INTO prof FROM public.banking_customer_profiles WHERE owner_type=app.applicant_type AND owner_id=app.applicant_id; SELECT COALESCE(sum(outstanding_principal_minor),0) INTO exposure FROM public.loan_contracts WHERE provider_id=prov.id AND status IN ('active','grace_period','delinquent','defaulted'); max_amt := LEAST(prod.maximum_amount_minor, GREATEST(0,(COALESCE((app.income_snapshot->>'average_income_minor')::bigint, prod.income_requirement_minor) * prod.affordability_threshold_basis_points / 10000) * GREATEST(prod.minimum_term_months,LEAST(app.requested_term_months,prod.maximum_term_months)))); approved := prov.status='active' AND NOT prov.lending_frozen AND app.currency_code=ANY(prov.supported_currencies) AND app.currency_code=ANY(prod.supported_currencies) AND app.applicant_type=ANY(prod.eligible_owner_types) AND app.purpose=ANY(prod.allowed_purposes) AND app.requested_amount_minor BETWEEN prod.minimum_amount_minor AND prod.maximum_amount_minor AND prof.credit_score >= GREATEST(prov.minimum_credit_score,prod.minimum_credit_score) AND exposure + app.requested_amount_minor <= prov.maximum_exposure_minor AND app.requested_amount_minor <= max_amt; IF approved THEN reasons := ARRAY['Credit score meets product minimum','Requested purpose and currency are supported','Affordability and provider exposure limits pass']; rate := prod.base_interest_rate_basis_points + prov.base_lending_margin_basis_points + GREATEST(0,(700-prof.credit_score)/10)*25; FOR sched IN SELECT * FROM public.calculate_equal_instalment_schedule(app.requested_amount_minor,rate,app.requested_term_months,(CURRENT_DATE + interval '1 month')::date) LOOP payment := GREATEST(payment,sched.total_due_minor); total_interest := total_interest + sched.scheduled_interest_minor; END LOOP; ELSE rejections := ARRAY_REMOVE(ARRAY[CASE WHEN prov.status<>'active' OR prov.lending_frozen THEN 'Provider is not currently lending' END, CASE WHEN NOT (app.currency_code=ANY(prov.supported_currencies) AND app.currency_code=ANY(prod.supported_currencies)) THEN 'Currency is not supported' END, CASE WHEN NOT (app.applicant_type=ANY(prod.eligible_owner_types)) THEN 'Borrower type is not eligible' END, CASE WHEN NOT (app.purpose=ANY(prod.allowed_purposes)) THEN 'Loan purpose is not eligible for this product' END, CASE WHEN prof.credit_score < GREATEST(prov.minimum_credit_score,prod.minimum_credit_score) THEN 'Credit score is below the minimum' END, CASE WHEN app.requested_amount_minor > max_amt THEN 'Affordability limit is below requested amount' END, CASE WHEN exposure + app.requested_amount_minor > prov.maximum_exposure_minor THEN 'Provider exposure limit would be exceeded' END], NULL); rate := NULL; END IF; INSERT INTO public.underwriting_results(application_id,approved,maximum_approved_amount_minor,offered_interest_rate_basis_points,offered_term_months,scheduled_payment_minor,total_interest_minor,total_repayment_minor,fees_minor,affordability_ratio_basis_points,risk_band,approval_reasons,rejection_reasons) VALUES(app.id,approved,max_amt,rate,CASE WHEN approved THEN app.requested_term_months END,CASE WHEN approved THEN payment END,CASE WHEN approved THEN total_interest ELSE 0 END,CASE WHEN approved THEN app.requested_amount_minor+total_interest ELSE 0 END,CASE WHEN approved THEN round(app.requested_amount_minor*prod.origination_fee_basis_points::numeric/10000)::bigint+prod.origination_fee_flat_minor ELSE 0 END,prod.affordability_threshold_basis_points,CASE WHEN prof.credit_score>=760 THEN 'low' WHEN prof.credit_score>=560 THEN 'medium' ELSE 'high' END,reasons,rejections) ON CONFLICT(application_id) DO UPDATE SET approved=EXCLUDED.approved, maximum_approved_amount_minor=EXCLUDED.maximum_approved_amount_minor, offered_interest_rate_basis_points=EXCLUDED.offered_interest_rate_basis_points, scheduled_payment_minor=EXCLUDED.scheduled_payment_minor, total_interest_minor=EXCLUDED.total_interest_minor, total_repayment_minor=EXCLUDED.total_repayment_minor, rejection_reasons=EXCLUDED.rejection_reasons RETURNING id INTO res; IF approved THEN INSERT INTO public.loan_offers(application_id,principal_minor,currency_code,interest_rate_basis_points,term_months,payment_frequency,scheduled_payment_minor,origination_fee_minor,total_interest_minor,total_repayment_minor,first_payment_date,grace_period_days,early_repayment_terms,late_payment_terms,offer_expires_at) SELECT app.id,app.requested_amount_minor,app.currency_code,rate,app.requested_term_months,prod.payment_frequency,payment,round(app.requested_amount_minor*prod.origination_fee_basis_points::numeric/10000)::bigint+prod.origination_fee_flat_minor,total_interest,app.requested_amount_minor+total_interest+round(app.requested_amount_minor*prod.origination_fee_basis_points::numeric/10000)::bigint+prod.origination_fee_flat_minor,(CURRENT_DATE + interval '1 month')::date,prod.grace_period_days,jsonb_build_object('partial_rule','shorten_term','fee_bps',prod.early_repayment_fee_basis_points),prod.late_payment_rule,timezone('utc',now())+interval '7 days' ON CONFLICT(application_id) DO NOTHING; UPDATE public.loan_applications SET status='offer_issued', reviewed_at=timezone('utc',now()), decision_reason='Approved by transparent affordability rules', offered_terms=(SELECT to_jsonb(o) FROM public.loan_offers o WHERE o.application_id=app.id) WHERE id=app.id; ELSE UPDATE public.loan_applications SET status='rejected', reviewed_at=timezone('utc',now()), decision_reason=array_to_string(rejections,'; ') WHERE id=app.id; PERFORM public.record_credit_score_event(app.applicant_type,app.applicant_id,-5,'loan_application_rejected','A recent application was declined after affordability or eligibility checks','loan_application',app.id); END IF; INSERT INTO public.banking_audit_events(action,entity_type,entity_id,provider_id,reason,new_value) VALUES('loan_application_decision','loan_application',app.id,app.provider_id,'automated underwriting completed',(SELECT to_jsonb(u) FROM public.underwriting_results u WHERE u.id=res)); RETURN res; END $$;

CREATE OR REPLACE FUNCTION public.accept_loan_offer(p_offer_id uuid,p_disbursement_bank_account_id uuid,p_repayment_bank_account_id uuid,p_idempotency_key text) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE offer public.loan_offers; app public.loan_applications; prod public.loan_products; disb public.bank_accounts; repay public.bank_accounts; contract_id uuid; tx uuid; sched record; fee bigint; obligation uuid; BEGIN SELECT id INTO contract_id FROM public.loan_contracts WHERE metadata->>'acceptance_idempotency_key'=p_idempotency_key; IF contract_id IS NOT NULL THEN RETURN contract_id; END IF; SELECT * INTO offer FROM public.loan_offers WHERE id=p_offer_id FOR UPDATE; IF offer.id IS NULL OR offer.status<>'issued' OR offer.offer_expires_at <= timezone('utc',now()) THEN RAISE EXCEPTION 'loan offer is not acceptable'; END IF; SELECT * INTO app FROM public.loan_applications WHERE id=offer.application_id FOR UPDATE; SELECT * INTO prod FROM public.loan_products WHERE id=app.product_id; SELECT * INTO disb FROM public.bank_accounts WHERE id=p_disbursement_bank_account_id FOR UPDATE; SELECT * INTO repay FROM public.bank_accounts WHERE id=p_repayment_bank_account_id; IF disb.owner_type<>app.applicant_type OR disb.owner_id<>app.applicant_id OR repay.owner_type<>app.applicant_type OR repay.owner_id<>app.applicant_id THEN RAISE EXCEPTION 'bank account does not belong to borrower'; END IF; IF disb.currency_code<>offer.currency_code OR repay.currency_code<>offer.currency_code THEN RAISE EXCEPTION 'loan accounts must match loan currency unless explicit conversion is quoted'; END IF; IF disb.status NOT IN ('active','restricted') OR repay.status<>'active' THEN RAISE EXCEPTION 'bank account is not eligible'; END IF; tx := public.finance_transfer('system',NULL,app.applicant_type,app.applicant_id,offer.principal_minor,'loan_disbursement','Loan principal disbursement; liability, not income','loan-disbursement-'||p_idempotency_key,'loan_offer',offer.id,app.created_by_profile_id,jsonb_build_object('taxable',false,'liability',true,'provider_id',app.provider_id,'bank_account_id',disb.id)); fee := offer.origination_fee_minor; INSERT INTO public.loan_contracts(borrower_type,borrower_id,provider_id,product_id,offer_id,repayment_bank_account_id,disbursement_bank_account_id,principal_minor,currency_code,outstanding_principal_minor,interest_rate_basis_points,rate_type,term_months,maturity_date,payment_frequency,scheduled_payment_minor,next_payment_date,total_payments,purpose,linked_entity_type,linked_entity_id,credit_score_at_origination,affordability_snapshot,status,disbursement_transaction_id,metadata) VALUES(app.applicant_type,app.applicant_id,app.provider_id,app.product_id,offer.id,repay.id,disb.id,offer.principal_minor,offer.currency_code,offer.principal_minor,offer.interest_rate_basis_points,offer.rate_type,offer.term_months,offer.first_payment_date + ((offer.term_months-1)||' months')::interval,offer.payment_frequency,offer.scheduled_payment_minor,offer.first_payment_date,offer.term_months,app.purpose,app.related_entity_type,app.related_entity_id,app.credit_score_snapshot,app.affordability_result,'active',tx,jsonb_build_object('acceptance_idempotency_key',p_idempotency_key,'principal_is_income',false)) RETURNING id INTO contract_id; FOR sched IN SELECT * FROM public.calculate_equal_instalment_schedule(offer.principal_minor,offer.interest_rate_basis_points,offer.term_months,offer.first_payment_date) LOOP INSERT INTO public.loan_schedule_lines(loan_contract_id,instalment_number,due_date,opening_principal_minor,scheduled_principal_minor,scheduled_interest_minor,total_due_minor) VALUES(contract_id,sched.instalment_number,sched.due_date,sched.opening_principal_minor,sched.scheduled_principal_minor,sched.scheduled_interest_minor,sched.total_due_minor); END LOOP; INSERT INTO public.recurring_financial_obligations(owner_type,owner_id,owner_account_id,expense_category,description,amount_minor,currency_code,frequency,next_due_date,related_entity_type,related_entity_id,auto_pay_enabled,grace_period_days,priority,metadata) VALUES(app.applicant_type,app.applicant_id,repay.linked_finance_account_id,'loan_principal_repayment','Scheduled loan repayment',offer.scheduled_payment_minor,offer.currency_code,offer.payment_frequency,offer.first_payment_date,'loan_contract',contract_id,true,offer.grace_period_days,10,jsonb_build_object('allocation_order',ARRAY['late_fee','accrued_interest','scheduled_interest','principal'])) RETURNING id INTO obligation; UPDATE public.loan_contracts SET recurring_obligation_id=obligation WHERE id=contract_id; UPDATE public.loan_offers SET status='accepted', accepted_at=timezone('utc',now()) WHERE id=offer.id; UPDATE public.loan_applications SET status='offer_accepted' WHERE id=app.id; UPDATE public.banking_customer_profiles SET total_borrowing_minor=total_borrowing_minor+offer.principal_minor, available_credit_minor=GREATEST(0,available_credit_minor-offer.principal_minor), updated_at=timezone('utc',now()) WHERE owner_type=app.applicant_type AND owner_id=app.applicant_id; INSERT INTO public.banking_audit_events(action,entity_type,entity_id,provider_id,reason,new_value) VALUES('loan_acceptance','loan_contract',contract_id,app.provider_id,'borrower explicitly accepted fixed-rate offer',jsonb_build_object('disbursement_transaction_id',tx,'principal_is_income',false)); RETURN contract_id; END $$;

CREATE OR REPLACE FUNCTION public.process_due_loan_repayments(p_as_of date DEFAULT CURRENT_DATE) RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE line record; loan public.loan_contracts; tx uuid; paid int:=0; fee_due bigint; principal_due bigint; interest_due bigint; total_due bigint; BEGIN FOR line IN SELECT l.* FROM public.loan_schedule_lines l JOIN public.loan_contracts c ON c.id=l.loan_contract_id WHERE c.status IN ('active','grace_period','delinquent') AND l.due_date<=p_as_of AND l.status IN ('scheduled','due','grace_period','late','seriously_late','final_warning','partial') ORDER BY l.due_date FOR UPDATE SKIP LOCKED LOOP SELECT * INTO loan FROM public.loan_contracts WHERE id=line.loan_contract_id FOR UPDATE; principal_due := line.scheduled_principal_minor - line.principal_paid_minor; interest_due := line.scheduled_interest_minor - line.interest_paid_minor; fee_due := line.scheduled_fee_minor - line.fee_paid_minor; total_due := GREATEST(0,principal_due)+GREATEST(0,interest_due)+GREATEST(0,fee_due); IF total_due <= 0 THEN CONTINUE; END IF; BEGIN tx := public.finance_transfer(loan.borrower_type,loan.borrower_id,'system',NULL,total_due,'loan_principal_repayment','Loan repayment allocated fee, interest, principal','loan-repayment-'||line.id||'-'||p_as_of,'loan_contract',loan.id,NULL,jsonb_build_object('allocation_order','late_fee,accrued_interest,scheduled_interest,principal','principal_minor',GREATEST(0,principal_due),'interest_minor',GREATEST(0,interest_due),'fee_minor',GREATEST(0,fee_due))); INSERT INTO public.loan_payments(loan_contract_id,schedule_line_id,amount_minor,principal_minor,interest_minor,fee_minor,currency_code,payment_type,transaction_id,idempotency_key) VALUES(loan.id,line.id,total_due,GREATEST(0,principal_due),GREATEST(0,interest_due),GREATEST(0,fee_due),loan.currency_code,'scheduled',tx,'loan-payment-'||line.id||'-'||p_as_of) ON CONFLICT DO NOTHING; UPDATE public.loan_schedule_lines SET amount_paid_minor=total_due, principal_paid_minor=scheduled_principal_minor, interest_paid_minor=scheduled_interest_minor, fee_paid_minor=scheduled_fee_minor, status='paid', payment_transaction_id=tx WHERE id=line.id; UPDATE public.loan_contracts SET outstanding_principal_minor=GREATEST(0,outstanding_principal_minor-GREATEST(0,principal_due)), amount_repaid_minor=amount_repaid_minor+total_due, interest_paid_minor=interest_paid_minor+GREATEST(0,interest_due), fees_paid_minor=fees_paid_minor+GREATEST(0,fee_due), payments_made=payments_made+1, next_payment_date=(SELECT min(due_date) FROM public.loan_schedule_lines WHERE loan_contract_id=loan.id AND status<>'paid') WHERE id=loan.id; PERFORM public.record_credit_score_event(loan.borrower_type,loan.borrower_id,8,'loan_repayment_on_time','A scheduled loan repayment was completed on time','loan_contract',loan.id); paid := paid + 1; EXCEPTION WHEN others THEN UPDATE public.recurring_financial_obligations SET failure_count=failure_count+1,last_attempted_at=timezone('utc',now()),status='failed' WHERE related_entity_type='loan_contract' AND related_entity_id=loan.id; END; END LOOP; UPDATE public.loan_contracts SET status='paid_off', outstanding_principal_minor=0, completed_at=timezone('utc',now()) WHERE status IN ('active','grace_period','delinquent') AND outstanding_principal_minor=0 AND NOT EXISTS (SELECT 1 FROM public.loan_schedule_lines l WHERE l.loan_contract_id=loan_contracts.id AND l.status<>'paid'); RETURN paid; END $$;

CREATE OR REPLACE FUNCTION public.progress_loan_delinquency(p_as_of date DEFAULT CURRENT_DATE) RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE r record; changed int:=0; new_stage public.loan_schedule_line_status; impact int; late_fee bigint; BEGIN FOR r IN SELECT l.*,c.borrower_type,c.borrower_id,c.id contract_id,c.product_id,c.status contract_status,p.late_payment_rule,p.grace_period_days FROM public.loan_schedule_lines l JOIN public.loan_contracts c ON c.id=l.loan_contract_id JOIN public.loan_products p ON p.id=c.product_id WHERE l.status <> 'paid' AND l.due_date < p_as_of FOR UPDATE SKIP LOCKED LOOP IF p_as_of - r.due_date <= r.grace_period_days THEN new_stage:='grace_period'; impact:=0; ELSIF p_as_of-r.due_date < 30 THEN new_stage:='late'; impact:=-25; ELSIF p_as_of-r.due_date < 60 THEN new_stage:='seriously_late'; impact:=-50; ELSIF p_as_of-r.due_date < 90 THEN new_stage:='final_warning'; impact:=-75; ELSE new_stage:='defaulted'; impact:=-120; END IF; late_fee := CASE WHEN new_stage IN ('late','seriously_late','final_warning') AND NOT r.late_fee_applied THEN LEAST(COALESCE((r.late_payment_rule->>'flat_fee_minor')::bigint,0),COALESCE((r.late_payment_rule->>'cap_minor')::bigint,2500)) ELSE 0 END; UPDATE public.loan_schedule_lines SET status=new_stage, days_overdue=p_as_of-due_date, scheduled_fee_minor=scheduled_fee_minor+late_fee, total_due_minor=total_due_minor+late_fee, late_fee_applied=late_fee_applied OR late_fee>0 WHERE id=r.id AND status IS DISTINCT FROM new_stage; IF FOUND THEN INSERT INTO public.loan_delinquency_records(loan_contract_id,schedule_line_id,stage,days_overdue,credit_impact_points,late_fee_minor,notification_key) VALUES(r.contract_id,r.id,new_stage,p_as_of-r.due_date,impact,late_fee,'loan-delinquency-'||r.id||'-'||new_stage) ON CONFLICT DO NOTHING; PERFORM public.record_credit_score_event(r.borrower_type,r.borrower_id,impact,'loan_'||new_stage::text,'Loan repayment status changed to '||new_stage::text,'loan_contract',r.contract_id); changed:=changed+1; END IF; IF new_stage='defaulted' AND r.contract_status<>'defaulted' THEN UPDATE public.loan_contracts SET status='defaulted', defaulted_at=timezone('utc',now()) WHERE id=r.contract_id; INSERT INTO public.loan_default_records(loan_contract_id,defaulted_amount_minor,principal_minor,interest_minor,fees_minor,recovery_options) VALUES(r.contract_id,r.total_due_minor-r.amount_paid_minor,r.opening_principal_minor-r.principal_paid_minor,r.scheduled_interest_minor-r.interest_paid_minor,r.scheduled_fee_minor-r.fee_paid_minor,jsonb_build_object('pay_arrears',true,'restructure',true,'refinance_if_eligible',true,'owner_or_member_contribution',true)) ON CONFLICT DO NOTHING; END IF; END LOOP; RETURN changed; END $$;

CREATE OR REPLACE VIEW public.loan_integrity_issues AS
SELECT 'loan_principal_without_disbursement_transaction' issue_type,id::text subject_id FROM public.loan_contracts WHERE status<>'cancelled' AND disbursement_transaction_id IS NULL
UNION ALL SELECT 'loan_disbursement_classified_as_income',c.id::text FROM public.loan_contracts c JOIN public.financial_transactions t ON t.id=c.disbursement_transaction_id WHERE t.transaction_category<>'loan_disbursement' OR COALESCE((t.metadata->>'taxable')::boolean,true)
UNION ALL SELECT 'loan_without_repayment_schedule',c.id::text FROM public.loan_contracts c WHERE NOT EXISTS(SELECT 1 FROM public.loan_schedule_lines l WHERE l.loan_contract_id=c.id)
UNION ALL SELECT 'principal_below_zero',id::text FROM public.loan_contracts WHERE outstanding_principal_minor<0
UNION ALL SELECT 'paid_off_loan_with_remaining_balance',id::text FROM public.loan_contracts WHERE status='paid_off' AND outstanding_principal_minor<>0
UNION ALL SELECT 'loan_payment_without_ledger_transaction',id::text FROM public.loan_payments WHERE transaction_id IS NULL
UNION ALL SELECT 'late_fee_duplicated',schedule_line_id::text FROM public.loan_delinquency_records WHERE late_fee_minor>0 GROUP BY schedule_line_id HAVING count(*)>1
UNION ALL SELECT 'default_without_overdue_schedule',d.loan_contract_id::text FROM public.loan_default_records d WHERE NOT EXISTS(SELECT 1 FROM public.loan_schedule_lines l WHERE l.loan_contract_id=d.loan_contract_id AND l.status='defaulted')
UNION ALL SELECT 'credit_score_outside_allowed_range',id::text FROM public.banking_customer_profiles WHERE credit_score<0 OR credit_score>1000
UNION ALL SELECT 'bank_account_balance_mismatch',ba.id::text FROM public.bank_accounts ba JOIN public.financial_accounts fa ON fa.id=ba.linked_finance_account_id LEFT JOIN (SELECT account_id,COALESCE(sum(CASE WHEN entry_direction='credit' THEN amount_minor ELSE -amount_minor END),0) bal FROM public.financial_ledger_entries GROUP BY account_id) s ON s.account_id=fa.id WHERE fa.owner_type<>'system' AND fa.current_balance_minor<>COALESCE(s.bal,0)
UNION ALL SELECT 'savings_interest_without_funding_transaction',id::text FROM public.deposit_interest_accruals WHERE status='paid' AND linked_transaction_id IS NULL
UNION ALL SELECT 'duplicate_active_repayment_obligation',related_entity_id::text FROM public.recurring_financial_obligations WHERE related_entity_type='loan_contract' AND status='active' GROUP BY related_entity_id HAVING count(*)>1
UNION ALL SELECT 'unsupported_loan_currency',c.id::text FROM public.loan_contracts c JOIN public.banking_providers p ON p.id=c.provider_id WHERE NOT (c.currency_code=ANY(p.supported_currencies))
UNION ALL SELECT 'provider_exposure_mismatch',p.id::text FROM public.banking_providers p WHERE COALESCE((SELECT sum(outstanding_principal_minor) FROM public.loan_contracts c WHERE c.provider_id=p.id AND c.status IN ('active','grace_period','delinquent','defaulted')),0) > p.maximum_exposure_minor;

CREATE OR REPLACE VIEW public.banking_dashboard_summary AS SELECT bp.owner_type,bp.owner_id,bp.credit_score,bp.credit_band,COALESCE(sum(c.outstanding_principal_minor),0) outstanding_principal_minor,COALESCE(sum(c.accrued_interest_minor),0) accrued_interest_minor,min(c.next_payment_date) next_payment_date,COALESCE(sum(CASE WHEN l.due_date<=CURRENT_DATE+7 AND l.status<>'paid' THEN l.total_due_minor-l.amount_paid_minor ELSE 0 END),0) payments_due_week_minor,COALESCE(sum(CASE WHEN l.due_date<CURRENT_DATE AND l.status<>'paid' THEN l.total_due_minor-l.amount_paid_minor ELSE 0 END),0) overdue_amount_minor FROM public.banking_customer_profiles bp LEFT JOIN public.loan_contracts c ON c.borrower_type=bp.owner_type AND c.borrower_id=bp.owner_id LEFT JOIN public.loan_schedule_lines l ON l.loan_contract_id=c.id GROUP BY bp.owner_type,bp.owner_id,bp.credit_score,bp.credit_band;

CREATE OR REPLACE FUNCTION public.assess_insolvency(p_owner_type public.financial_owner_type,p_owner_id uuid) RETURNS public.insolvency_assessment_outcome LANGUAGE plpgsql STABLE AS $$ DECLARE cash bigint; overdue bigint; debt bigint; BEGIN SELECT COALESCE(sum(current_balance_minor),0) INTO cash FROM public.financial_accounts WHERE owner_type=p_owner_type AND owner_id=p_owner_id; SELECT COALESCE(sum(total_due_minor-amount_paid_minor),0) INTO overdue FROM public.loan_schedule_lines l JOIN public.loan_contracts c ON c.id=l.loan_contract_id WHERE c.borrower_type=p_owner_type AND c.borrower_id=p_owner_id AND l.due_date<CURRENT_DATE AND l.status<>'paid'; SELECT COALESCE(sum(outstanding_principal_minor),0) INTO debt FROM public.loan_contracts WHERE borrower_type=p_owner_type AND borrower_id=p_owner_id AND status IN ('active','grace_period','delinquent','defaulted'); RETURN CASE WHEN overdue > cash AND debt > cash*3 THEN 'insolvent'::public.insolvency_assessment_outcome WHEN overdue > cash THEN 'at_risk_of_insolvency'::public.insolvency_assessment_outcome WHEN overdue > 0 THEN 'financially_distressed'::public.insolvency_assessment_outcome WHEN debt > cash*2 THEN 'liquidity_warning'::public.insolvency_assessment_outcome ELSE 'solvent'::public.insolvency_assessment_outcome END; END $$;

