ALTER TABLE public.banking_providers ENABLE ROW LEVEL SECURITY; ALTER TABLE public.banking_customer_profiles ENABLE ROW LEVEL SECURITY; ALTER TABLE public.bank_accounts ENABLE ROW LEVEL SECURITY; ALTER TABLE public.loan_products ENABLE ROW LEVEL SECURITY; ALTER TABLE public.loan_applications ENABLE ROW LEVEL SECURITY; ALTER TABLE public.loan_offers ENABLE ROW LEVEL SECURITY; ALTER TABLE public.loan_contracts ENABLE ROW LEVEL SECURITY; ALTER TABLE public.loan_schedule_lines ENABLE ROW LEVEL SECURITY; ALTER TABLE public.loan_payments ENABLE ROW LEVEL SECURITY; ALTER TABLE public.credit_score_events ENABLE ROW LEVEL SECURITY; ALTER TABLE public.banking_audit_events ENABLE ROW LEVEL SECURITY;
CREATE POLICY banking_providers_public_select ON public.banking_providers FOR SELECT USING (status IN ('active','restricted'));
CREATE POLICY loan_products_public_select ON public.loan_products FOR SELECT USING (status IN ('active','restricted'));
CREATE POLICY banking_profiles_owner_select ON public.banking_customer_profiles FOR SELECT USING ((owner_type='player' AND EXISTS(SELECT 1 FROM public.profiles p WHERE p.id=owner_id AND p.user_id=auth.uid())) OR (owner_type='band' AND EXISTS(SELECT 1 FROM public.band_members bm JOIN public.profiles p ON p.id=bm.profile_id WHERE bm.band_id=owner_id AND p.user_id=auth.uid())) OR (owner_type='company' AND EXISTS(SELECT 1 FROM public.companies c WHERE c.id=owner_id AND c.owner_id=auth.uid())));
CREATE POLICY bank_accounts_owner_select ON public.bank_accounts FOR SELECT USING ((owner_type='player' AND EXISTS(SELECT 1 FROM public.profiles p WHERE p.id=owner_id AND p.user_id=auth.uid())) OR (owner_type='band' AND EXISTS(SELECT 1 FROM public.band_members bm JOIN public.profiles p ON p.id=bm.profile_id WHERE bm.band_id=owner_id AND p.user_id=auth.uid())) OR (owner_type='company' AND EXISTS(SELECT 1 FROM public.companies c WHERE c.id=owner_id AND c.owner_id=auth.uid())));
CREATE POLICY loan_applications_owner_select ON public.loan_applications FOR SELECT USING ((applicant_type='player' AND EXISTS(SELECT 1 FROM public.profiles p WHERE p.id=applicant_id AND p.user_id=auth.uid())) OR (applicant_type='band' AND EXISTS(SELECT 1 FROM public.band_members bm JOIN public.profiles p ON p.id=bm.profile_id WHERE bm.band_id=applicant_id AND p.user_id=auth.uid())) OR (applicant_type='company' AND EXISTS(SELECT 1 FROM public.companies c WHERE c.id=applicant_id AND c.owner_id=auth.uid())));
CREATE POLICY loan_contracts_owner_select ON public.loan_contracts FOR SELECT USING ((borrower_type='player' AND EXISTS(SELECT 1 FROM public.profiles p WHERE p.id=borrower_id AND p.user_id=auth.uid())) OR (borrower_type='band' AND EXISTS(SELECT 1 FROM public.band_members bm JOIN public.profiles p ON p.id=bm.profile_id WHERE bm.band_id=borrower_id AND p.user_id=auth.uid())) OR (borrower_type='company' AND EXISTS(SELECT 1 FROM public.companies c WHERE c.id=borrower_id AND c.owner_id=auth.uid())));
CREATE POLICY loan_schedule_owner_select ON public.loan_schedule_lines FOR SELECT USING (EXISTS(SELECT 1 FROM public.loan_contracts c WHERE c.id=loan_contract_id));
CREATE POLICY banking_audit_admin_select ON public.banking_audit_events FOR SELECT USING (public.has_role(auth.uid(),'admin'));
